define(["core/ajax","core/notification"],function(Ajax,Notification){function showIndicator(select,success){var indicator=select.parentElement.querySelector(".rangeos-save-indicator");if(!indicator){return}indicator.textContent=success?"✓":"✗";indicator.className="rangeos-save-indicator ml-2 "+(success?"text-success":"text-danger");indicator.style.display="";setTimeout(function(){indicator.style.display="none"},2500)}function assignEnvironment(select){var cmi5id=parseInt(select.dataset.cmi5id,10);var envid=parseInt(select.value,10);if(!cmi5id){return}if(envid===0){showIndicator(select,true);return}select.disabled=true;Ajax.call([{methodname:"local_rangeos_apply_environment_profile",args:{envid:envid,cmi5ids:[cmi5id]}}])[0].then(function(){showIndicator(select,true);var row=select.closest("tr");if(row){row.dataset.currentEnvid=envid}}).catch(function(err){showIndicator(select,false);Notification.exception(err);var row=select.closest("tr");if(row){select.value=row.dataset.currentEnvid||"0"}}).finally(function(){select.disabled=false})}function init(){var courseFilter=document.querySelector("[data-action='filter-course']");if(courseFilter){courseFilter.addEventListener("change",function(e){var baseUrl=document.querySelector("[data-baseurl]");if(baseUrl){var url=baseUrl.dataset.baseurl;var sep=url.includes("?")?"&":"?";window.location.href=url+sep+"courseid="+e.target.value}})}document.addEventListener("change",function(e){var select=e.target.closest("[data-action='assign-environment']");if(select){assignEnvironment(select)}})}return{init:init}});
